package com.projectbible.shop.gradle.jpa.postgresql.product.application;
import java.util.List; import java.util.Map; import java.util.stream.Collectors; import org.springframework.stereotype.Service;
@Service public class ProductQueryService { private final List<Map<String,Object>> items=List.of(Map.of("id",1,"categoryId",1,"name","Project Bible Handbook","description","Printed handbook","price",19000,"stock",50,"status","ACTIVE"),Map.of("id",2,"categoryId",2,"name","Project Bible Mug","description","Ceramic mug","price",12000,"stock",20,"status","ACTIVE")); public List<Map<String,Object>> list(Long categoryId) { return items.stream().filter(i->categoryId==null||((Number)i.get("categoryId")).longValue()==categoryId).map(this::summary).collect(Collectors.toList()); } public Map<String,Object> one(long id) { return items.stream().filter(i->((Number)i.get("id")).longValue()==id).findFirst().orElseThrow(()->new IllegalArgumentException("Product not found: "+id)); } private Map<String,Object> summary(Map<String,Object> product) { return Map.of("id",product.get("id"),"categoryId",product.get("categoryId"),"name",product.get("name"),"price",product.get("price"),"stock",product.get("stock"),"status",product.get("status")); } }
